ALTER TABLE profiles DROP CONSTRAINT IF EXISTS profiles_visual_style_check; ALTER TABLE profiles ADD CONSTRAINT profiles_visual_style_check CHECK (visual_style = ANY (ARRAY['classic'::text, 'minimalist'::text, 'cyberpunk'::text, 'glassmorphism'::text, 'neo-brutalism'::text, 'romantic'::text, 'elegant'::text, 'royal-khmer'::text, 'white-minimal'::text, 'cinematic-dark'::text, 'editorial'::text]));;
